128.             catch (Exception ex)
129.             {
130.                 Trace.TraceError($"Error creating student: {ex.Message} | Student: {student?.FirstMidName} {student?.LastName} | EnrollmentDate: {student?.EnrollmentDate} | Stack: {ex.StackTrace}");
131.                 ModelState.AddModelError("", "Unable to save changes. Try again, and if the problem persists see your system administrator.");
132.             }
133.             return View(student);
134.         }
