using System;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests
{
    public static class TestHelpers
    {
        public static SchoolContext CreateInMemoryContext()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;

            var context = new SchoolContext(options);
            return context;
        }

        public static SchoolContext CreateSeededContext()
        {
            var context = CreateInMemoryContext();
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var instructor1 = new Instructor
            {
                ID = 1,
                LastName = "Abercrombie",
                FirstMidName = "Kim",
                HireDate = DateTime.Parse("1995-03-11"),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };
            var instructor2 = new Instructor
            {
                ID = 2,
                LastName = "Fakhouri",
                FirstMidName = "Fadi",
                HireDate = DateTime.Parse("2002-07-06"),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };

            context.Instructors.AddRange(instructor1, instructor2);

            var department1 = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 1
            };
            var department2 = new Department
            {
                DepartmentID = 2,
                Name = "Mathematics",
                Budget = 100000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 2
            };

            context.Departments.AddRange(department1, department2);

            var course1 = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            var course2 = new Course
            {
                CourseID = 4022,
                Title = "Microeconomics",
                Credits = 3,
                DepartmentID = 2
            };

            context.Courses.AddRange(course1, course2);

            var student1 = new Student
            {
                ID = 1,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.Parse("2010-09-01")
            };
            var student2 = new Student
            {
                ID = 2,
                LastName = "Alonso",
                FirstMidName = "Meredith",
                EnrollmentDate = DateTime.Parse("2012-09-01")
            };
            var student3 = new Student
            {
                ID = 3,
                LastName = "Anand",
                FirstMidName = "Arturo",
                EnrollmentDate = DateTime.Parse("2013-09-01")
            };

            context.Students.AddRange(student1, student2, student3);

            var enrollment1 = new Enrollment { EnrollmentID = 1, CourseID = 1050, StudentID = 1, Grade = Grade.A };
            var enrollment2 = new Enrollment { EnrollmentID = 2, CourseID = 4022, StudentID = 1, Grade = Grade.C };
            var enrollment3 = new Enrollment { EnrollmentID = 3, CourseID = 1050, StudentID = 2, Grade = Grade.B };

            context.Enrollments.AddRange(enrollment1, enrollment2, enrollment3);

            context.SaveChanges();
        }
    }
}

using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_WithAllParameters_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", "Carson Alexander", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("Carson Alexander", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SimpleOverload_WithoutDisplayName()
        {
            _service.SendNotification("Department", "5", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Department", notification.EntityType);
            Assert.Equal("5", notification.EntityId);
            Assert.Equal("DELETE", notification.Operation);
            Assert.Contains("Department (ID: 5)", notification.Message);
        }

        [Fact]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("New Student 'John Doe' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "100", "Physics", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("Course 'Physics' has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("Department 'Engineering' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", null, EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.Contains("Student (ID: 42)", notification.Message);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            var before = DateTime.Now.AddSeconds(-1);

            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            var after = DateTime.Now.AddSeconds(1);

            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
        {
            var result = _service.ReceiveNotification();

            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_DequeuesInFIFOOrder()
        {
            _service.SendNotification("Student", "1", "First", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", "Second", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.Equal("Student", first.EntityType);
            Assert.Equal("Course", second.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_WithEmptyDisplayName_UsesIdFallback()
        {
            _service.SendNotification("Student", "7", "   ", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();

            Assert.Contains("Student (ID: 7)", notification.Message);
        }
    }
}

using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPageOfItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(1, result[0]);
            Assert.Equal(10, result[9]);
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(11, result[0]);
            Assert.Equal(20, result[9]);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(5, result.Count);
            Assert.Equal(21, result[0]);
            Assert.Equal(25, result[4]);
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(3, result.TotalPages);
        }

        [Fact]
        public void TotalPages_ExactMultiple_CalculatedCorrectly()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(2, result.TotalPages);
        }

        [Fact]
        public void PageIndex_SetsCorrectly()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(2, result.PageIndex);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void Create_SinglePage_NoNextNoPrevious()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
            Assert.Equal(1, result.TotalPages);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
        }

        [Fact]
        public void Constructor_SetsPropertiesCorrectly()
        {
            var items = new List<string> { "a", "b", "c" };

            var result = new PaginatedList<string>(items, 30, 2, 10);

            Assert.Equal(3, result.Count);
            Assert.Equal(2, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
        }
    }
}

