using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests
{
    public static class TestHelpers
    {
        public static SchoolContext CreateInMemoryContext()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;

            var context = new SchoolContext(options);
            return context;
        }

        public static SchoolContext CreateSeededContext()
        {
            var context = CreateInMemoryContext();
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var instructor1 = new Instructor
            {
                ID = 1,
                LastName = "Abercrombie",
                FirstMidName = "Kim",
                HireDate = DateTime.Parse("1995-03-11"),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };
            var instructor2 = new Instructor
            {
                ID = 2,
                LastName = "Fakhouri",
                FirstMidName = "Fadi",
                HireDate = DateTime.Parse("2002-07-06"),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };

            context.Instructors.AddRange(instructor1, instructor2);

            var department1 = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 1
            };
            var department2 = new Department
            {
                DepartmentID = 2,
                Name = "Mathematics",
                Budget = 100000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 2
            };

            context.Departments.AddRange(department1, department2);

            var course1 = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            var course2 = new Course
            {
                CourseID = 4022,
                Title = "Microeconomics",
                Credits = 3,
                DepartmentID = 2
            };

            context.Courses.AddRange(course1, course2);

            var student1 = new Student
            {
                ID = 1,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.Parse("2010-09-01")
            };
            var student2 = new Student
            {
                ID = 2,
                LastName = "Alonso",
                FirstMidName = "Meredith",
                EnrollmentDate = DateTime.Parse("2012-09-01")
            };
            var student3 = new Student
            {
                ID = 3,
                LastName = "Anand",
                FirstMidName = "Arturo",
                EnrollmentDate = DateTime.Parse("2013-09-01")
            };

            context.Students.AddRange(student1, student2, student3);

            var enrollment1 = new Enrollment { EnrollmentID = 1, CourseID = 1050, StudentID = 1, Grade = Grade.A };
            var enrollment2 = new Enrollment { EnrollmentID = 2, CourseID = 4022, StudentID = 1, Grade = Grade.C };
            var enrollment3 = new Enrollment { EnrollmentID = 3, CourseID = 1050, StudentID = 2, Grade = Grade.B };

            context.Enrollments.AddRange(enrollment1, enrollment2, enrollment3);

            context.SaveChanges();
        }
    }
}

