using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Anand", model[2].LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Anand", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Alexander", model[2].LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            var result = _controller.Index("Date", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Anand", model[2].LastName);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Anand", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Alexander", model[2].LastName);
        }

        [Fact]
        public void Index_SearchString_FiltersResults()
        {
            var result = _controller.Index(null, null, "Alexander", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Meredith", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Alonso", model[0].LastName);
        }

        [Fact]
        public void Index_SearchString_ResetsPageTo1()
        {
            var result = _controller.Index(null, null, "A", 3);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            var result = _controller.Index("Date", null, "test", null) as ViewResult;

            Assert.Equal("Date", result.ViewData["CurrentSort"]);
            Assert.Equal("date_desc", result.ViewData["DateSortParm"]);
            Assert.Equal("", result.ViewData["NameSortParm"]);
            Assert.Equal("test", result.ViewData["CurrentFilter"]);
        }

        [Fact]
        public void Index_EmptySort_NameSortParmIsNameDesc()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.Equal("name_desc", result.ViewData["NameSortParm"]);
            Assert.Equal("Date", result.ViewData["DateSortParm"]);
        }

        [Fact]
        public void Details_ValidId_ReturnsStudentWithEnrollments()
        {
            var result = _controller.Details(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal("Alexander", model.LastName);
            Assert.NotNull(model.Enrollments);
            Assert.Equal(2, model.Enrollments.Count);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Create(student);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_Post_ValidStudent_SavesInDb()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            _controller.Create(student);

            Assert.Equal(4, _context.Students.Count());
            Assert.Contains(_context.Students, s => s.LastName == "NewStudent");
        }

        [Fact]
        public void Create_Post_InvalidEnrollmentDate_MinValue_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_InvalidEnrollmentDate_TooEarly_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(1700, 1, 1)
            };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Edit(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal("Alexander", model.LastName);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "UpdatedAlexander",
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.Parse("2010-09-01")
            };
            // Detach the existing tracked entity
            var existing = _context.Students.Find(1);
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(student);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidEnrollmentDate_ReturnsView()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student);

            Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Delete(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal("Alexander", model.LastName);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(2, _context.Students.Count());
            Assert.DoesNotContain(_context.Students, s => s.ID == 1);
        }
    }
}

