using System;
using System.IO;
using System.Linq;
using System.Text;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempPath;

        public CoursesControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _tempPath = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempPath);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempPath);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempPath);
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempPath))
            {
                Directory.Delete(_tempPath, true);
            }
        }

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(viewResult.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithCourse()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Course>(viewResult.Model);
        }

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 3000,
                Title = "New Course",
                Credits = 4,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_Post_ValidCourse_SavesInDb()
        {
            var course = new Course
            {
                CourseID = 3000,
                Title = "New Course",
                Credits = 4,
                DepartmentID = 1
            };

            _controller.Create(course, null);

            Assert.Equal(3, _context.Courses.Count());
            Assert.Contains(_context.Courses, c => c.Title == "New Course");
        }

        [Fact]
        public void Create_Post_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course();

            var result = _controller.Create(course, null);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Create_Post_WithValidImage_SavesFile()
        {
            var course = new Course
            {
                CourseID = 3001,
                Title = "With Image",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.jpg", "image content", 100);

            var result = _controller.Create(course, mockFile.Object);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            var savedCourse = _context.Courses.Find(3001);
            Assert.NotNull(savedCourse.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_InvalidImageExtension_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 3002,
                Title = "Bad Image",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.exe", "content", 100);

            var result = _controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_ImageTooLarge_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 3003,
                Title = "Large Image",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.jpg", "content", 6 * 1024 * 1024);

            var result = _controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Edit(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Updated Chemistry",
                Credits = 4,
                DepartmentID = 1
            };
            var existing = _context.Courses.Find(1050);
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(course, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050 };

            var result = _controller.Edit(course, null);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_Post_InvalidImageExtension_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            var existing = _context.Courses.Find(1050);
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            var mockFile = CreateMockFormFile("test.txt", "content", 100);

            var result = _controller.Edit(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Post_ImageTooLarge_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            var existing = _context.Courses.Find(1050);
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            var mockFile = CreateMockFormFile("test.png", "content", 6 * 1024 * 1024);

            var result = _controller.Edit(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1050);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.DoesNotContain(_context.Courses, c => c.CourseID == 1050);
        }

        [Fact]
        public void Edit_Post_WithValidImage_UpdatesImagePath()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            var existing = _context.Courses.Find(1050);
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            var mockFile = CreateMockFormFile("new_image.png", "image data", 500);

            var result = _controller.Edit(course, mockFile.Object);

            Assert.IsType<RedirectToActionResult>(result);
            var savedCourse = _context.Courses.Find(1050);
            Assert.NotNull(savedCourse.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

        private Mock<IFormFile> CreateMockFormFile(string fileName, string content, long length)
        {
            var mockFile = new Mock<IFormFile>();
            var stream = new MemoryStream(Encoding.UTF8.GetBytes(content));
            mockFile.Setup(f => f.FileName).Returns(fileName);
            mockFile.Setup(f => f.Length).Returns(length);
            mockFile.Setup(f => f.OpenReadStream()).Returns(stream);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => stream.CopyTo(s));
            return mockFile;
        }
    }
}

