using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class SchoolContextTests
    {
        [Fact]
        public void SchoolContext_CanCreateAndQueryStudents()
        {
            var context = TestHelpers.CreateInMemoryContext();
            context.Students.Add(new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            });
            context.SaveChanges();

            Assert.Single(context.Students);
        }

        [Fact]
        public void SchoolContext_CanCreateAndQueryCourses()
        {
            var context = TestHelpers.CreateInMemoryContext();
            context.Departments.Add(new Department
            {
                DepartmentID = 1,
                Name = "Test",
                Budget = 10000,
                StartDate = DateTime.Now
            });
            context.Courses.Add(new Course
            {
                CourseID = 100,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1
            });
            context.SaveChanges();

            Assert.Single(context.Courses);
            Assert.Equal("Test Course", context.Courses.First().Title);
        }

        [Fact]
        public void SchoolContext_CanCreateAndQueryInstructors()
        {
            var context = TestHelpers.CreateInMemoryContext();
            context.Instructors.Add(new Instructor
            {
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = DateTime.Parse("2020-01-01")
            });
            context.SaveChanges();

            Assert.Single(context.Instructors);
        }

        [Fact]
        public void SchoolContext_CanCreateAndQueryDepartments()
        {
            var context = TestHelpers.CreateInMemoryContext();
            context.Departments.Add(new Department
            {
                Name = "Physics",
                Budget = 50000,
                StartDate = DateTime.Parse("2020-09-01")
            });
            context.SaveChanges();

            Assert.Single(context.Departments);
        }

        [Fact]
        public void SchoolContext_CanCreateAndQueryEnrollments()
        {
            var context = TestHelpers.CreateSeededContext();

            Assert.Equal(3, context.Enrollments.Count());
        }

        [Fact]
        public void SchoolContext_CourseAssignment_CompositeKey()
        {
            var context = TestHelpers.CreateSeededContext();
            context.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 1050
            });
            context.SaveChanges();

            var assignment = context.CourseAssignments.Find(1050, 1);
            Assert.NotNull(assignment);
        }

        [Fact]
        public void SchoolContext_SeededData_HasCorrectCounts()
        {
            var context = TestHelpers.CreateSeededContext();

            Assert.Equal(3, context.Students.Count());
            Assert.Equal(2, context.Instructors.Count());
            Assert.Equal(2, context.Departments.Count());
            Assert.Equal(2, context.Courses.Count());
            Assert.Equal(3, context.Enrollments.Count());
        }
    }
}

