using System;
using System.Linq;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    [Collection("NotificationServiceTests")]
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain the static queue to avoid cross-test pollution
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        private Notification FindNotification(string entityId)
        {
            // Drain until we find our notification (handles potential race with other tests)
            Notification found = null;
            Notification n;
            int maxAttempts = 100;
            while (maxAttempts-- > 0 && (n = _service.ReceiveNotification()) != null)
            {
                if (n.EntityId == entityId)
                {
                    found = n;
                    break;
                }
            }
            return found;
        }

        [Fact]
        public void SendNotification_WithAllParameters_EnqueuesNotification()
        {
            var uniqueId = Guid.NewGuid().ToString();
            _service.SendNotification("Student", uniqueId, "Carson Alexander", EntityOperation.CREATE, "Admin");

            var notification = FindNotification(uniqueId);

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal(uniqueId, notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("Carson Alexander", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            var uniqueId = Guid.NewGuid().ToString();
            _service.SendNotification("Course", uniqueId, "Chemistry", EntityOperation.UPDATE);

            var notification = FindNotification(uniqueId);

            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SimpleOverload_WithoutDisplayName()
        {
            var uniqueId = Guid.NewGuid().ToString();
            _service.SendNotification("Department", uniqueId, EntityOperation.DELETE);

            var notification = FindNotification(uniqueId);

            Assert.NotNull(notification);
            Assert.Equal("Department", notification.EntityType);
            Assert.Equal(uniqueId, notification.EntityId);
            Assert.Equal("DELETE", notification.Operation);
            Assert.Contains($"Department (ID: {uniqueId})", notification.Message);
        }

        [Fact]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage()
        {
            var uniqueId = Guid.NewGuid().ToString();
            _service.SendNotification("Student", uniqueId, "John Doe", EntityOperation.CREATE);

            var notification = FindNotification(uniqueId);

            Assert.NotNull(notification);
            Assert.Equal("New Student 'John Doe' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            var uniqueId = Guid.NewGuid().ToString();
            _service.SendNotification("Course", uniqueId, "Physics", EntityOperation.UPDATE);

            var notification = FindNotification(uniqueId);

            Assert.NotNull(notification);
            Assert.Equal("Course 'Physics' has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            var uniqueId = Guid.NewGuid().ToString();
            _service.SendNotification("Department", uniqueId, "Engineering", EntityOperation.DELETE);

            var notification = FindNotification(uniqueId);

            Assert.NotNull(notification);
            Assert.Equal("Department 'Engineering' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            var uniqueId = Guid.NewGuid().ToString();
            _service.SendNotification("Student", uniqueId, null, EntityOperation.CREATE);

            var notification = FindNotification(uniqueId);

            Assert.NotNull(notification);
            Assert.Contains($"Student (ID: {uniqueId})", notification.Message);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            var before = DateTime.Now.AddSeconds(-1);
            var uniqueId = Guid.NewGuid().ToString();

            _service.SendNotification("Student", uniqueId, "Test", EntityOperation.CREATE);

            var notification = FindNotification(uniqueId);
            var after = DateTime.Now.AddSeconds(1);

            Assert.NotNull(notification);
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
        {
            // Drain everything first
            while (_service.ReceiveNotification() != null) { }

            var result = _service.ReceiveNotification();

            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_DequeuesInFIFOOrder()
        {
            var id1 = Guid.NewGuid().ToString();
            var id2 = Guid.NewGuid().ToString();
            _service.SendNotification("Student", id1, "First", EntityOperation.CREATE);
            _service.SendNotification("Course", id2, "Second", EntityOperation.UPDATE);

            var first = FindNotification(id1);
            var second = FindNotification(id2);

            Assert.NotNull(first);
            Assert.NotNull(second);
            Assert.Equal("Student", first.EntityType);
            Assert.Equal("Course", second.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            var uniqueId = Guid.NewGuid().ToString();
            _service.SendNotification("Student", uniqueId, EntityOperation.CREATE);

            var first = FindNotification(uniqueId);
            var second = FindNotification(uniqueId);

            Assert.NotNull(first);
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_WithEmptyDisplayName_UsesIdFallback()
        {
            var uniqueId = Guid.NewGuid().ToString();
            _service.SendNotification("Student", uniqueId, "   ", EntityOperation.UPDATE);

            var notification = FindNotification(uniqueId);

            Assert.NotNull(notification);
            Assert.Contains($"Student (ID: {uniqueId})", notification.Message);
        }
    }
}

